import React, { useState } from "react";
import CalendarGrid from "./CalendarGrid";
import events from "../../data/events";
import "./Calendar.css";

const Calendar = () => {
  const today = new Date();

  const [currentDate, setCurrentDate] = useState(
    new Date(today.getFullYear(), today.getMonth(), 1)
  );
  const [view, setView] = useState("month");
  const [filters, setFilters] = useState({
    holiday: true,
    leave: true,
    birthday: true,
  });

  const changeMonth = (step) => {
    setCurrentDate(
      new Date(currentDate.getFullYear(), currentDate.getMonth() + step, 1)
    );
  };

  const toggleFilter = (type) => {
    setFilters({ ...filters, [type]: !filters[type] });
  };

  return (
    <div className="calendar-wrapper">
      {/* FILTER SIDEBAR */}
      <div className="calendar-sidebar">
        <h3>Filters</h3>

        <label>
          <input
            type="checkbox"
            checked={filters.holiday}
            onChange={() => toggleFilter("holiday")}
          />
          Holidays (Green)
        </label>

        <label>
          <input
            type="checkbox"
            checked={filters.leave}
            onChange={() => toggleFilter("leave")}
          />
          Leaves (Yellow)
        </label>

        <label>
          <input
            type="checkbox"
            checked={filters.birthday}
            onChange={() => toggleFilter("birthday")}
          />
          Birthdays (Blue)
        </label>
      </div>

      {/* CALENDAR */}
      <div className="calendar-content">
        <div className="calendar-header">
          <button className="btn btn-active">Month</button>

          <button className="btn" onClick={() => changeMonth(-1)}>
            Prev
          </button>

          <span className="month-label">
            {currentDate.toLocaleString("default", {
              month: "long",
              year: "numeric",
            })}
          </span>

          <button className="btn" onClick={() => changeMonth(1)}>
            Next
          </button>

          <button
            className={`btn ${view === "week" ? "btn-active" : ""}`}
            onClick={() => setView("week")}
          >
            Week
          </button>
        </div>

        <CalendarGrid
          date={currentDate}
          events={events}
          filters={filters}
          view={view}
        />
      </div>
    </div>
  );
};

export default Calendar;
